# ── Session receiver — relays ScriptRunner callbacks ─────────────────────────

_SESSION_SERVICE = "org.kwinlib.Session"
_SESSION_PATH    = "/Receiver"
_SESSION_IFACE   = "org.kwinlib.Session"

_SESSION_XML = f"""
<node>
  <interface name='{_SESSION_IFACE}'>
    <method name='receiveResult'>
      <arg type='s' name='test_name' direction='in'/>
      <arg type='s' name='json_data' direction='in'/>
    </method>
  </interface>
</node>
"""


class _SessionReceiver(CallbackReceiver):
    dbus = _SESSION_XML


# ── KWinSession ───────────────────────────────────────────────────────────────

class KWinSession:
    """
    Context manager that owns all shared D-Bus infrastructure for a session.

    Sets up:
      - pydbus SessionBus
      - GLib main loop (background thread)
      - KWinBus (connections to KWin services)
      - ScriptRunner (loads/runs/unloads KWin JS snippets)
      - D-Bus receiver service (org.kwinlib.Session)
      - DesktopManager, WindowManager, WindowProbe

    Usage:
        with KWinSession() as kwin:
            desktops = kwin.desktops.list_desktops()
            screens  = kwin.desktops.list_screens()
            pid, wins = kwin.probe.run(["thunderbird"])
            kwin.windows.maximize(wins[0].internalId)
    """

    def __init__(self, verbose: bool = False) -> None:
        self._bus:          SessionBus | None         = None
        self._loop:         GLibLoop   | None         = None
        self._kwin:         KWinBus    | None         = None
        self._runner:       ScriptRunner | None       = None
        self._receiver:     _SessionReceiver | None   = None
        self._registration: Any                       = None
        self._verbose:      bool                      = verbose

        self.desktops: DesktopManager | None = None
        self.windows:  WindowManager  | None = None
        self.probe:    WindowProbe    | None = None

    def open(self) -> "KWinSession":
        """Initialise infrastructure.  Called automatically by __enter__."""
        self._bus  = SessionBus()
        self._loop = GLibLoop()
        self._loop.start()

        self._kwin = KWinBus(self._bus)

        # Smoke-test connection
        try:
            self._kwin.scripting.isScriptLoaded("__smoke_test__")
        except Exception as exc:
            raise RuntimeError(
                f"Cannot connect to KWin D-Bus scripting interface: {exc}\n"
                "Is KDE Plasma / KWin running?"
            ) from exc

        # Publish receiver service for ScriptRunner callbacks
        receiver = _SessionReceiver()
        try:
            self._registration = self._bus.publish(
                _SESSION_SERVICE, (_SESSION_PATH, receiver)
            )
        except Exception as exc:
            raise RuntimeError(
                f"Cannot publish session receiver '{_SESSION_SERVICE}': {exc}\n"
                "Is another KWinSession already open?"
            ) from exc

        self._runner   = ScriptRunner(
            self._kwin, _SESSION_SERVICE, _SESSION_PATH, _SESSION_IFACE
        )
        receiver._runner = self._runner   # wire up callback relay

        self.desktops = DesktopManager(self._kwin, self._runner)
        self.windows  = WindowManager(self._kwin, self._runner, verbose=self._verbose)
        self.probe    = WindowProbe()     # uses its own bus/receiver internally

        return self

    def close(self) -> None:
        """Release all resources."""
        try:
            if self._registration is not None:
                self._registration.unpublish()
        except Exception: pass
        try:
            if self._loop is not None:
                self._loop.stop()
        except Exception: pass
        self._bus = self._loop = self._kwin = self._runner = None
        self._registration = None

    def __enter__(self) -> "KWinSession":
        return self.open()

    def __exit__(self, *_) -> None:
        self.close()


# ── Module-level convenience functions ────────────────────────────────────────

def launch_and_place(
    command:      str | list[str],
    *,
    desktop:      str | int | None = None,   # name, 1-based number, "*", or "all"
    screen:       str | int | None = None,   # connector name or index
    maximize:     bool             = True,
    timeout_secs: float            = 30.0,
    filter_class: str              = "",
    relaunch:     bool             = False,
) -> WindowInfo:
    """
    High-level convenience: launch a program (or find it if already running),
    move its window to the specified desktop/screen, and maximize it.

    Pass desktop="*" or desktop="all" to make the window visible on all
    virtual desktops.

    Returns the WindowInfo of the placed window.
    Raises RuntimeError on any failure.

    Examples:
        win = launch_and_place("thunderbird",
                               desktop="Main", screen="HDMI-A-2")

        win = launch_and_place("brave",
                               desktop="*", screen="main")  # all desktops
    """
    if isinstance(command, str):
        command = [command]

    _ALL_INPUTS = {"*", "all"}

    with KWinSession() as kwin:
        # Identify window
        probe     = WindowProbe(
            timeout_secs = timeout_secs,
            filter_class = filter_class,
            stop_count   = 1,
            relaunch     = relaunch,
        )
        pid, wins = probe.run(command)
        if not wins:
            raise RuntimeError(
                f"No window detected for {command!r} within {timeout_secs}s"
            )
        win  = wins[0]
        uuid = win.internalId

        # Detect all-desktops sentinel
        wants_all = isinstance(desktop, str) and desktop.lower() in _ALL_INPUTS

        # Resolve desktop object (unless all-desktops or unspecified)
        target_desktop: DesktopInfo | str | None = None
        if wants_all:
            target_desktop = "*"   # pass sentinel through to place()
        elif desktop is not None:
            if isinstance(desktop, int):
                target_desktop = kwin.desktops.find_desktop(number=desktop)
            else:
                target_desktop = kwin.desktops.find_desktop(name=desktop)
            if target_desktop is None:
                raise RuntimeError(f"Desktop not found: {desktop!r}")

        # Resolve screen
        target_screen: ScreenInfo | None = None
        if screen is not None:
            if isinstance(screen, int):
                target_screen = kwin.desktops.find_screen(index=screen)
            else:
                target_screen = kwin.desktops.find_screen(name=screen)
            if target_screen is None:
                raise RuntimeError(f"Screen not found: {screen!r}")

        # Place the window
        kwin.windows.place(
            uuid,
            desktop   = target_desktop,
            screen    = target_screen,
            maximize  = maximize,
            raise_win = True,
        )

        return win


